        self.status_combo.addItems(["Active", "Scheduled", "Draft"])
        form.addRow(lbl("Status"), self.status_combo)

        self.body_edit = QtWidgets.QTextEdit()
        self.body_edit.setPlaceholderText("Write the announcement body here...")
        self.body_edit.setFixedHeight(90)
        form.addRow(lbl("Body"), self.body_edit)

        root.addLayout(form)

        if self._edit and data:
            self.title_edit.setText(data.get("title",""))
            idx = self.type_combo.findText(data.get("type",""))
            if idx >= 0: self.type_combo.setCurrentIndex(idx)
            idx = self.priority_combo.findText(data.get("priority",""))
            if idx >= 0: self.priority_combo.setCurrentIndex(idx)
            idx = self.audience_combo.findText(data.get("audience",""))
            if idx >= 0: self.audience_combo.setCurrentIndex(idx)
