    # ──────────────────────────────────────────────────────────────────────────
    # TABLE POPULATION
    # ──────────────────────────────────────────────────────────────────────────
    def _populate_table(self, data: list = None):
        rows = data if data is not None else self._announcements
        self.table.setRowCount(0)
        for i, ann in enumerate(rows):
            ann_id, title, a_type, priority, audience, status, pub_on = ann
            self.table.insertRow(i)
            self.table.setRowHeight(i, 46)

            self._set_item(i, 0, str(i + 1))
            self._set_item(i, 1, title)

            # Type badge
            tfg, tbg = TYPE_COLOURS.get(a_type, (_TEXT_MID,"#f3f4f6"))
            self.table.setCellWidget(i, 2, self._centre(_Badge(a_type, tfg, tbg)))

            # Priority badge
            pfg, pbg = PRIORITY_COLOURS.get(priority, (_TEXT_MID,"#f3f4f6"))
            self.table.setCellWidget(i, 3, self._centre(_Badge(priority, pfg, pbg)))

            # Audience with icon
            aud_ico = AUDIENCE_ICONS.get(audience, "👥")
            self._set_item(i, 4, f"{aud_ico} {audience}")

            # Status badge
            sfg, sbg = STATUS_COLOURS.get(status, (_TEXT_MID,"#f3f4f6"))
            self.table.setCellWidget(i, 5, self._centre(_Badge(status, sfg, sbg)))

            self._set_item(i, 6, pub_on)
            self.table.setCellWidget(i, 7, self._action_widget(i))

        count = len(rows)
        self.showing_lbl.setText(
            f"Showing 1 to {min(10, count)} of {count} announcements")

    def _set_item(self, row, col, text):
        it = QtWidgets.QTableWidgetItem(text)
        it.setFlags(it.flags() & ~Qt.ItemFlag.ItemIsEditable)
        self.table.setItem(row, col, it)

    @staticmethod
    def _centre(widget) -> QtWidgets.QWidget:
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.addWidget(widget)
        hl.setAlignment(Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter)
        hl.setContentsMargins(6, 0, 0, 0)
        return w

    def _action_widget(self, row: int) -> QtWidgets.QWidget:
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.setContentsMargins(4, 0, 4, 0); hl.setSpacing(4)
        for ico, tip, col, slot in [
            ("👁","View",  "#64748b", lambda _, r=row: self._on_view(r)),
            ("✏","Edit",  "#2563eb", lambda _, r=row: self._on_edit(r)),
            ("🗑","Delete","#dc2626", lambda _, r=row: self._on_delete(r)),
        ]:
            b = QtWidgets.QPushButton(ico)
            b.setFixedSize(26, 26); b.setToolTip(tip)
            b.setCursor(QtGui.QCursor(Qt.CursorShape.PointingHandCursor))
            b.setStyleSheet(f"""
                QPushButton {{
                    background:{col}22; color:{col};
                    border:1px solid {col}44;
                    border-radius:5px; font-size:12px;
                }}
                QPushButton:hover {{ background:{col}44; }}
            """)
            b.clicked.connect(slot); hl.addWidget(b)
        hl.addStretch()
        return w

    # ──────────────────────────────────────────────────────────────────────────
    # SLOTS
    # ──────────────────────────────────────────────────────────────────────────
    def _on_tab(self, tab: str):
        self._active_tab = tab
        for name, btn in self._tab_btns.items():
            btn.setStyleSheet(self._tab_style(name == tab))
        self._apply_filters()

    def _apply_filters(self):
        text = self.search_edit.text().lower()
        tab  = self._active_tab
        results = []
        for ann in self._announcements:
            ann_id, title, a_type, priority, audience, status, pub_on = ann
            if tab == "Active"    and status != "Active":    continue
            if tab == "Scheduled" and status != "Scheduled": continue
            if tab == "Expired"   and status != "Expired":   continue
            if tab == "Drafts"    and status != "Draft":     continue
            if text and not any(text in v.lower() for v in
                                (title, a_type, priority, audience, status)):
                continue
            results.append(ann)
        self._populate_table(results)

    def _on_new(self):
        dlg = NewAnnouncementDialog(self)
        dlg.announcement_saved.connect(self._append_announcement)
        dlg.exec()

    def _append_announcement(self, data: dict):
        new_id = len(self._announcements) + 1
        from datetime import datetime
        pub = datetime.now().strftime("%d %b %Y %I:%M %p")
        self._announcements.insert(0, (
            new_id, data["title"], data["type"],
            data["priority"], data["audience"], data["status"], pub
        ))
        self._apply_filters()
        QtWidgets.QMessageBox.information(
            self, "Announcement Published",
            f"✅  '{data['title']}' has been published successfully."
        )

    def _on_view(self, row: int):
        if row >= len(self._announcements): return
        a = self._announcements[row]
        QtWidgets.QMessageBox.information(
            self, "Announcement Details",
            f"<b>{a[1]}</b><br>Type: {a[2]}<br>Priority: {a[3]}<br>"
            f"Audience: {a[4]}<br>Status: {a[5]}<br>Published: {a[6]}"
        )

    def _on_edit(self, row: int):
        if row >= len(self._announcements): return
        a = self._announcements[row]
        dlg = NewAnnouncementDialog(self, data={
            "title": a[1], "type": a[2], "priority": a[3],
            "audience": a[4], "status": a[5],
        })
        dlg.announcement_saved.connect(lambda data, r=row: self._save_edit(r, data))
        dlg.exec()

    def _save_edit(self, row: int, data: dict):
        old = self._announcements[row]
        self._announcements[row] = (
            old[0], data["title"], data["type"],
            data["priority"], data["audience"], data["status"], old[6]
        )
        self._apply_filters()

    def _on_delete(self, row: int):
        if row >= len(self._announcements): return
        name = self._announcements[row][1]
        reply = QtWidgets.QMessageBox.question(
            self, "Delete Announcement",
            f"Delete <b>{name}</b>? This cannot be undone.",
            QtWidgets.QMessageBox.StandardButton.Yes |
            QtWidgets.QMessageBox.StandardButton.No,
            QtWidgets.QMessageBox.StandardButton.No,
        )
        if reply == QtWidgets.QMessageBox.StandardButton.Yes:
            self._announcements.pop(row)
            self._apply_filters()

    def _on_filter_menu(self):
        QtWidgets.QMessageBox.information(
            self, "Advanced Filters",
            "Advanced filter panel will be available in the next sprint."
        )

    def _on_export(self):
        QtWidgets.QMessageBox.information(
            self, "Export",
            "Export functionality will be connected in the next sprint."
        )

    def _on_placeholder(self):
        QtWidgets.QMessageBox.information(
            self, "Coming Soon",
            "This feature will be available in the next sprint."
        )

